remediations.oracle_command:
-- View execution plan:
SELECT * FROM TABLE(DBMS_XPLAN.DISPLAY_AWR('bm5q4vbp3tuvv'));
-- Run SQL Tuning Advisor:
DECLARE l_task VARCHAR2(100);
BEGIN
  l_task := DBMS_SQLTUNE.CREATE_TUNING_TASK(sql_id=>'bm5q4vbp3tuvv', scope=>DBMS_SQLTUNE.SCOPE_COMPREHENSIVE, time_limit=>60, task_name=>'TUNE_bm5q4vbp3tuvv');
  DBMS_SQLTUNE.EXECUTE_TUNING_TASK(task_name=>'TUNE_bm5q4vbp3tuvv');
END;
/
SELECT DBMS_SQLTUNE.REPORT_TUNING_TASK('TUNE_bm5q4vbp3tuvv') FROM dual;

-- Check redo log location:
SELECT group#, member FROM v$logfile ORDER BY group#;
-- Check log switch frequency:
SELECT TO_CHAR(first_time,'YYYY-MM-DD HH24') hr, COUNT(*) switches FROM v$log_history WHERE first_time > SYSDATE-1 GROUP BY TO_CHAR(first_time,'YYYY-MM-DD HH24') ORDER BY 1;

